module top_module(EN,
    D,
    CLK,
    Q_AND);output Q_AND;
  input EN;
  input [3:0] D;
  input CLK;

  reg [3:0] obf_Q;  // Changed wire to reg
  wire Q_AND;

  // Implement a 4-bit register with synchronous clear
  always @(posedge CLK) begin
    if (EN) begin
      obf_Q <= D;
    end else begin
      obf_Q <= 4'b0;
    end
  end

  // Implement the logical AND of the register's four bits
  assign Q_AND = obf_Q[0] & obf_Q[1] & obf_Q[2] & obf_Q[3];

endmodule
